const WORKS = [
{id:1,title:"Тихий Дон",author:"М. Шолохов",pages:"~1500 стр. (роман-эпопея)",adaptation:"Да, несколько экранизаций (1957, 2015)",tags:["война","семья","выбор"],
summary:"Роман-эпопея о судьбе донского казачества в годы Первой мировой, революции и Гражданской войны. Григорий Мелехов мечется между Аксиньей и женой Натальей, между красными и белыми, пытаясь найти правду в мире, где рушится привычный уклад жизни.",
characters:[{name:"Григорий Мелехов",desc:"главный герой, мечется между долгом и чувством, между красными и белыми"},{name:"Аксинья",desc:"возлюбленная Григория, символ трагической любви"},{name:"Наталья",desc:"законная жена Григория, воплощение верности"},{name:"Пантелей Прокофьевич",desc:"отец Григория, хранитель казачьих традиций"}],
arguments:["Война разрушает семьи и уклад жизни, стирает границы добра и зла.","Человек, оказавшийся между двумя лагерями, теряет себя — цена метаний Григория огромна.","Историческая катастрофа проверяет человека на прочность его нравственных устоев.","Любовь и долг часто вступают в неразрешимый конфликт."],
quote:{text:"Он стоял у ______ своего родного дома, не зная, куда ему теперь идти.",answer:"порога"},
keyFacts:[{q:"Что символизирует финал романа, когда Григорий возвращается домой?",a:"Крушение всех иллюзий и потерю всего, ради чего он боролся",distractors:["Полную победу над врагами","Начало новой счастливой жизни","Отказ от родного дома"]},{q:"Между какими лагерями мечется Григорий Мелехов?",a:"Между красными и белыми",distractors:["Между казаками и большевиками-иностранцами","Между церковью и властью","Между городом и деревней"]}],
tip:"Мнемоника: «Тихий Дон — тихо рушится дом» (война ломает семью и весь уклад)."},

{id:2,title:"Судьба человека",author:"М. Шолохов",pages:"~40 стр.",adaptation:"Да, фильм 1959 г. (реж. С. Бондарчук)",tags:["война","доброта","семья"],
summary:"Андрей Соколов теряет на войне всю семью, сам проходит через плен и лагеря, но сохраняет человечность. После победы он встречает мальчика-сироту Ванюшу и, назвавшись его отцом, усыновляет его — жизнь продолжается вопреки всем потерям.",
characters:[{name:"Андрей Соколов",desc:"рассказчик, солдат, потерявший семью на войне"},{name:"Ванюша",desc:"мальчик-сирота, которого усыновляет Соколов"}],
arguments:["Сила духа человека способна выстоять даже перед лицом абсолютной потери.","Доброта и способность заботиться о других — то, что остаётся у человека после трагедии.","Война отнимает у людей всё, но не может отнять человечность.","Усыновление Ванюши — акт нравственного возрождения после катастрофы."],
quote:{text:"Ты одна у меня ______ и радость, и надежда светлая на закате моих дней.",answer:"отрада"},
keyFacts:[{q:"Кого усыновляет Андрей Соколов в конце рассказа?",a:"Мальчика-сироту Ванюшу",distractors:["Племянника","Соседского ребёнка","Сына сослуживца"]},{q:"Что Соколов теряет на войне?",a:"Всю свою семью — жену, детей",distractors:["Только дом","Только работу","Ничего, семья выжила"]}],
tip:"Мнемоника: «Судьба отняла — Соколов дал» (потерял семью — обрёл сына)."},

{id:3,title:"Мастер и Маргарита",author:"М. Булгаков",pages:"~480 стр.",adaptation:"Да, несколько (сериал 2005, фильм 2024)",tags:["добро и зло","любовь","талант"],
summary:"Воланд и его свита появляются в Москве 1930-х, обнажая пороки общества. Параллельно разворачивается роман Мастера о Понтии Пилате и история любви Мастера и Маргариты, которая заключает сделку с дьяволом ради спасения возлюбленного.",
characters:[{name:"Мастер",desc:"писатель, сломленный травлей критиков"},{name:"Маргарита",desc:"возлюбленная Мастера, ради любви идёт на сделку с Воландом"},{name:"Воланд",desc:"дьявол, вершащий своеобразное правосудие над людскими пороками"},{name:"Понтий Пилат",desc:"герой романа Мастера, мучается трусостью, погубившей Иешуа"}],
arguments:["Трусость — главный порок, разрушающий человека (тема Понтия Пилата).","Настоящая любовь способна на самопожертвование ради спасения любимого.","Творческая свобода важнее конформизма — «рукописи не горят».","Общество, лишённое нравственных ориентиров, легко поддаётся мелким порокам."],
quote:{text:"______ не горят, — сказал Воланд, забирая обгоревшую тетрадь.",answer:"Рукописи"},
keyFacts:[{q:"На что идёт Маргарита ради спасения Мастера?",a:"Заключает сделку с Воландом, становится королевой на балу сатаны",distractors:["Уезжает за границу","Пишет донос на критиков","Уходит в монастырь"]},{q:"Какой порок Булгаков называет самым страшным в судьбе Понтия Пилата?",a:"Трусость",distractors:["Жадность","Гордыня","Лень"]}],
tip:"Мнемоника: «Рукописи не горят» = искусство и правда бессмертны."},

{id:4,title:"Собачье сердце",author:"М. Булгаков",pages:"~130 стр.",adaptation:"Да, фильм 1988 г. (реж. В. Бортко)",tags:["наука","мораль","общество"],
summary:"Профессор Преображенский пересаживает псу Шарику гипофиз человека, и тот превращается в грубого, наглого Шарикова, который начинает угрожать самому создателю. Эксперимент показывает опасность вмешательства в природу без нравственной ответственности.",
characters:[{name:"Профессор Преображенский",desc:"учёный, проводит рискованный эксперимент"},{name:"Шариков",desc:"пёс, превращённый в человека — воплощение агрессивного бескультурья"},{name:"Доктор Борменталь",desc:"ассистент профессора"}],
arguments:["Наука без нравственной ответственности несёт разрушение (учёный должен думать о последствиях).","Насильственное «улучшение» природы человека невозможно — воспитание важнее операции.","Революционная ломка старого мира без культуры порождает хаос и агрессию (Шариков как символ).","Автор предупреждает: вмешательство в естественный порядок вещей мстит своему создателю."],
quote:{text:"Разруха не в клозетах, а в ______.",answer:"головах"},
keyFacts:[{q:"В кого превращается пёс Шарик после операции?",a:"В грубого, агрессивного человека по фамилии Шариков",distractors:["В образованного интеллигента","Он умирает после операции","В точную копию профессора"]},{q:"Чем заканчивается эксперимент профессора?",a:"Преображенский проводит обратную операцию, возвращая Шарикова в пса",distractors:["Шариков становится директором института","Профессора арестовывают","Шариков женится"]}],
tip:"Мнемоника: «Собачье сердце — человеческий вред» (эксперимент без совести опасен)."},

{id:5,title:"Роковые яйца",author:"М. Булгаков",pages:"~90 стр.",adaptation:"Нет широко известной",tags:["наука","ответственность"],
summary:"Профессор Персиков открывает «луч жизни», ускоряющий рост организмов. Советские чиновники, желая быстро восстановить куриное поголовье, по ошибке используют луч на змеиных и крокодильих яйцах — по стране начинают шествовать гигантские рептилии.",
characters:[{name:"Профессор Персиков",desc:"учёный, случайно открывший опасный луч"},{name:"Рокк",desc:"партийный работник, из-за спешки и некомпетентности вызывает катастрофу"}],
arguments:["Научное открытие в руках некомпетентных и поспешных людей превращается в катастрофу.","Государственное давление на науку ради быстрого результата опасно.","Ответственность учёного не заканчивается на открытии — важно, кто и как его использует.","Сатира на бюрократическую спешку и безграмотное вмешательство власти в науку."],
quote:{text:"Луч ______ оказался в чужих и неумелых руках.",answer:"жизни"},
keyFacts:[{q:"Что открывает профессор Персиков?",a:"«Луч жизни», ускоряющий рост и размножение организмов",distractors:["Лекарство от всех болезней","Способ говорить с животными","Вечный двигатель"]},{q:"Из-за чего происходит катастрофа в повести?",a:"Чиновники по ошибке применяют луч на яйцах змей и крокодилов вместо куриных",distractors:["Персиков сам выпускает рептилий","Луч выходит из-под контроля сам по себе","Иностранные шпионы крадут луч"]}],
tip:"Мнемоника: «Роковые яйца — роковая спешка» (наука + спешка чиновников = катастрофа)."},

{id:6,title:"Телеграмма",author:"К. Паустовский",pages:"~15 стр.",adaptation:"Нет широко известной",tags:["семья","совесть"],
summary:"Настя живёт в городе, поглощённая карьерой, и постоянно откладывает поездку к одинокой стареющей матери Катерине Петровне. Когда та умирает, Настя получает телеграмму слишком поздно и не успевает даже на похороны — вина остаётся с ней навсегда.",
characters:[{name:"Настя",desc:"дочь, поглощённая работой, забывающая о матери"},{name:"Катерина Петровна",desc:"одинокая мать, тоскующая по дочери"}],
arguments:["Невнимание к родителям — непростительная ошибка, которую нельзя исправить после их смерти.","Настоящая забота требует не денег, а живого присутствия и времени.","Поздно осознанная вина — тяжёлый урок о ценности близких, пока они рядом.","Автор призывает не откладывать заботу о родных «на потом»."],
quote:{text:"Ненаглядная моя, ______ моя, — шептала старушка в темноту.",answer:"дочка"},
keyFacts:[{q:"Почему Настя не успевает к матери?",a:"Она откладывала поездку из-за занятости на работе",distractors:["Мать запретила ей приезжать","Не было денег на дорогу","Она не получила телеграмму совсем"]},{q:"Успевает ли Настя на похороны матери?",a:"Нет, она приезжает уже после похорон",distractors:["Да, успевает в последний момент","Мать выздоравливает","Настя вообще не приезжает"]}],
tip:"Мнемоника: «Телеграмма опоздала — Настя опоздала» (заботу нельзя откладывать)."},

{id:7,title:"Юшка",author:"А. Платонов",pages:"~10 стр.",adaptation:"Нет широко известной",tags:["доброта","общество","милосердие"],
summary:"Юшка — тихий, больной кузнечный подмастерье, над которым издеваются все в деревне, включая детей. Оказывается, он тайно откладывает всю зарплату на обучение приёмной девочки-сироты. После его смерти от побоев жители узнают правду, а девушка, выучившись на врача, возвращается и всю жизнь бесплатно лечит людей города.",
characters:[{name:"Юшка (Ефим Дмитриевич)",desc:"кроткий, безответный герой, тайно творящий добро"},{name:"Приёмная девочка",desc:"сирота, которую Юшка выучил на врача, продолжает его дело добра"}],
arguments:["Истинная доброта часто незаметна и не требует признания.","Общество склонно унижать «непохожих», не понимая их внутренней ценности — жестокость толпы.","Доброе дело одного человека способно продолжиться и умножиться в других (девушка-врач).","Истинную цену человека часто осознают только после его смерти."],
quote:{text:"А чем я хуже вас, я тоже ______ нужен на свете!",answer:"нужен"},
keyFacts:[{q:"На что Юшка тайно тратил все свои деньги?",a:"На обучение девочки-сироты в городе",distractors:["Копил на дом","Отправлял родственникам","Тратил на лекарства себе"]},{q:"Чем стала приёмная дочь Юшки, когда выросла?",a:"Врачом, которая бесплатно лечит всех в городе",distractors:["Учительницей","Она уехала и забыла о деревне","Стала кузнецом"]}],
tip:"Мнемоника: «Юшка — юродивая доброта» (незаметная жертвенность рождает продолжение добра)."},

{id:8,title:"Чудесный доктор",author:"А. Куприн",pages:"~10 стр.",adaptation:"Нет широко известной",tags:["доброта","чудо","милосердие"],
summary:"Накануне Рождества семья Мерцаловых оказывается на грани отчаяния: нищета, болезнь ребёнка, отец готов на самоубийство. Случайный прохожий — доктор Пирогов — бесплатно лечит больную девочку и оставляет деньги, круто изменив судьбу семьи.",
characters:[{name:"Мерцалов",desc:"отчаявшийся отец семейства"},{name:"Доктор Пирогов",desc:"случайный прохожий, спасающий семью актом милосердия"}],
arguments:["Доброта незнакомца может стать настоящим чудом и переломить судьбу человека.","Милосердие важнее социального статуса — помощь пришла от чужого человека, а не от близких.","Рождественский сюжет показывает: даже в момент отчаяния есть шанс на спасение.","Один добрый поступок способен изменить жизнь целой семьи на годы вперёд."],
quote:{text:"Вы, главное, не ______ духом, голубчик, — сказал доктор.",answer:"падайте"},
keyFacts:[{q:"Кто спасает семью Мерцаловых?",a:"Случайный прохожий, оказавшийся известным доктором Пироговым",distractors:["Соседи","Священник","Родственник из деревни"]},{q:"Когда происходит действие рассказа?",a:"Накануне Рождества",distractors:["Летом","На Пасху","В день рождения отца"]}],
tip:"Мнемоника: «Чудесный доктор — чудо от чужого» (помощь пришла оттуда, откуда не ждали)."},

{id:9,title:"Куст сирени",author:"А. Куприн",pages:"~8 стр.",adaptation:"Нет широко известной",tags:["семья","поддержка","любовь"],
summary:"Офицер Николай Алмазов допускает ошибку на топографической карте, нарисовав несуществующий куст сирени. Чтобы муж не провалил экзамен, его жена Вера закладывает украшения и организует ночную посадку настоящего куста сирени на указанном месте.",
characters:[{name:"Николай Алмазов",desc:"муж, совершивший ошибку на экзамене"},{name:"Вера Алмазова",desc:"находчивая жена, спасающая мужа своей изобретательностью"}],
arguments:["Взаимная поддержка в браке способна исправить, казалось бы, безвыходную ситуацию.","Находчивость и любовь важнее гордости — Вера жертвует украшениями ради мужа.","Настоящая любовь проявляется в готовности действовать, а не только сочувствовать.","Пара, действующая как команда, преодолевает трудности успешнее, чем поодиночке."],
quote:{text:"Вот всегда так у ______ бывает: сначала беда, а потом мы вместе её решаем.",answer:"нас"},
keyFacts:[{q:"Какую ошибку совершает Алмазов?",a:"Рисует на карте несуществующий куст сирени",distractors:["Опаздывает на экзамен","Теряет карту","Даёт неверный ответ профессору устно"]},{q:"Как Вера спасает мужа?",a:"Закладывает украшения и сажает настоящий куст сирени в указанном месте",distractors:["Уговаривает профессора","Пишет письмо в комиссию","Подделывает карту"]}],
tip:"Мнемоника: «Куст сирени — куёт семья» (совместные усилия решают проблему)."},

{id:10,title:"Тапёр",author:"А. Куприн",pages:"~8 стр.",adaptation:"Нет широко известной",tags:["талант","шанс"],
summary:"На рождественском вечере в богатом доме бедный юноша Юрий Азагаров неожиданно заменяет заболевшего тапёра. Его игру случайно слышит знаменитый композитор Антон Рубинштейн, который распознаёт в мальчике настоящий талант и берёт его под своё крыло.",
characters:[{name:"Юрий Азагаров",desc:"бедный талантливый подросток-музыкант"},{name:"Антон Рубинштейн",desc:"знаменитый композитор, разглядевший в мальчике гений"}],
arguments:["Истинный талант способен пробиться сквозь бедность и обстоятельства.","Случай и внимательный наставник могут изменить судьбу одарённого человека.","Настоящее искусство узнаётся сразу — оно не зависит от социального положения исполнителя.","Тема доброго покровительства: успешные люди способны заметить и поддержать чужой дар."],
quote:{text:"Кто ваш ______, мальчик? — спросил великий музыкант, поражённый игрой.",answer:"учитель"},
keyFacts:[{q:"Кем оказывается юный тапёр по сюжету?",a:"Талантливым бедным подростком Юрием Азагаровым",distractors:["Профессиональным музыкантом из консерватории","Сыном хозяев дома","Иностранным гостем"]},{q:"Кто замечает талант мальчика?",a:"Композитор Антон Рубинштейн",distractors:["Хозяин дома","Учитель музыки мальчика","Никто не замечает"]}],
tip:"Мнемоника: «Тапёр — талант в дверь стучится» (дар всегда находит свой шанс)."},

{id:11,title:"Сотников",author:"В. Быков",pages:"~120 стр.",adaptation:"Да, фильм «Восхождение» 1976 г.",tags:["война","выбор","предательство"],
summary:"Два партизана, Сотников и Рыбак, попадают в плен к немцам. Ослабленный болезнью Сотников остаётся верен себе до конца и принимает казнь с достоинством, а физически крепкий Рыбак ради спасения жизни соглашается сотрудничать с врагом и становится предателем и палачом товарища.",
characters:[{name:"Сотников",desc:"партизан, сохраняющий нравственную стойкость перед лицом смерти"},{name:"Рыбак",desc:"партизан, предающий товарища ради спасения собственной жизни"}],
arguments:["Война — это прежде всего испытание нравственного выбора, а не только физической силы.","Верность своим принципам важнее сохранения жизни любой ценой.","Предательство разрушает человека сильнее, чем смерть.","Героизм не всегда громкий — иногда это тихое достоинство перед казнью."],
quote:{text:"Он умирал так, как жил, — не предав ______.",answer:"никого"},
keyFacts:[{q:"Как поступает Рыбак, чтобы спастись?",a:"Соглашается сотрудничать с немцами и становится их пособником",distractors:["Сбегает из плена вместе с Сотниковым","Тоже принимает казнь","Его отпускают без условий"]},{q:"Как встречает смерть Сотников?",a:"С достоинством, не предав товарищей",distractors:["Просит пощады","Пытается бежать и погибает случайно","Соглашается на сотрудничество в последний момент"]}],
tip:"Мнемоника: «Сотников стойкий, Рыбак — рыбкой выскользнул» (стойкость против предательства)."},

{id:12,title:"Капитанская дочка",author:"А. Пушкин",pages:"~130 стр.",adaptation:"Да, несколько экранизаций",tags:["честь","милосердие","история"],
summary:"Молодой офицер Пётр Гринёв во время пугачёвского восстания проходит испытание честью и верностью присяге, сохраняя человечность даже к врагу — Пугачёву, который в ответ на добрый поступок Гринёва (тулупчик) щадит его. Любовь к Маше Мироновой и верность долгу помогают Гринёву выстоять.",
characters:[{name:"Пётр Гринёв",desc:"молодой дворянин, хранящий честь несмотря на обстоятельства"},{name:"Маша Миронова",desc:"капитанская дочка, возлюбленная Гринёва, воплощение стойкости и верности"},{name:"Емельян Пугачёв",desc:"предводитель восстания, способный на благодарность и милосердие"},{name:"Швабрин",desc:"антипод Гринёва, предаёт присягу ради выгоды"}],
arguments:["«Береги честь смолоду» — главный нравственный завет произведения.","Доброе дело (подаренный тулуп) возвращается добром даже от врага — милосердие важнее вражды.","Верность присяге и долгу проверяется в момент исторической смуты.","Противопоставление Гринёва и Швабрина показывает цену чести и цену предательства."],
quote:{text:"Береги ______ смолоду, а платье снову.",answer:"честь"},
keyFacts:[{q:"Почему Пугачёв щадит Гринёва?",a:"Помнит доброту Гринёва, подарившего ему заячий тулуп",distractors:["Гринёв подкупил его","Пугачёв не узнал Гринёва","Маша упросила Пугачёва"]},{q:"Как ведёт себя Швабрин во время восстания?",a:"Переходит на сторону Пугачёва, предав присягу",distractors:["Погибает, защищая крепость","Спасает Гринёва","Уезжает из крепости заранее"]}],
tip:"Мнемоника: «Капитанская дочка — честь испечена смолоду» (тулуп = добро вернулось добром)."},

{id:13,title:"Станционный смотритель",author:"А. Пушкин",pages:"~15 стр.",adaptation:"Да, фильм 1972 г.",tags:["семья","маленький человек","утрата"],
summary:"Самсон Вырин, одинокий станционный смотритель, теряет единственную радость — дочь Дуню, которую увозит гусар Минский. Отец пытается вернуть дочь, но безуспешно, и, тоскуя, спивается и умирает в одиночестве. Дуня, уже богатая дама, приезжает на его могилу слишком поздно.",
characters:[{name:"Самсон Вырин",desc:"станционный смотритель, «маленький человек», тоскующий по дочери"},{name:"Дуня",desc:"дочь Вырина, уезжает с гусаром, поздно осознаёт вину перед отцом"},{name:"Минский",desc:"гусар, увозящий Дуню из отчего дома"}],
arguments:["Тема «маленького человека» — беззащитность простого человека перед несправедливостью судьбы.","Уход детей без оглядки на родителей causa непоправимую трагедию (параллель с притчей о блудном сыне).","Позднее раскаяние не может вернуть утраченное — Дуня приезжает, когда отца уже нет.","Автор показывает цену родительской любви, которую редко ценят вовремя."],
quote:{text:"Много ли в самом деле надобно ______ старику: он был сыт, одет и имел добрую дочь.",answer:"человеку"},
keyFacts:[{q:"Кто увозит Дуню из дома отца?",a:"Гусар Минский",distractors:["Купец","Сосед-смотритель","Она уезжает одна"]},{q:"Чем заканчивается жизнь Самсона Вырина?",a:"Он спивается от тоски и умирает в одиночестве",distractors:["Он мирится с дочерью и живёт долго","Уезжает жить к дочери","Находит новую семью"]}],
tip:"Мнемоника: «Станционный смотритель — стой, дочка!» (уехала — и отец не дождался)."},

{id:14,title:"451 градус по Фаренгейту",author:"Р. Брэдбери",pages:"~200 стр.",adaptation:"Да, фильмы 1966 и 2018 гг.",tags:["антиутопия","цензура","мышление"],
summary:"В обществе будущего книги под запретом, а пожарные их сжигают. Пожарный Гай Монтэг, столкнувшись с думающей соседкой Клариссой и потерей смысла в собственной жизни, начинает читать книги тайно, осознаёт цену свободы мысли и в итоге присоединяется к хранителям запрещённых книг.",
characters:[{name:"Гай Монтэг",desc:"пожарный, сжигающий книги, проходит путь пробуждения"},{name:"Кларисса",desc:"юная соседка, пробуждающая в Монтэге способность думать и чувствовать"},{name:"Милдред",desc:"жена Монтэга, погружённая в бессмысленное потребление медиа"}],
arguments:["Цензура и уничтожение книг лишают общество способности мыслить критически.","Массовая культура и развлечения могут заменить живое человеческое мышление и общение.","Пробуждение личности часто начинается со случайной встречи, меняющей взгляд на мир.","Книги хранят память и опыт человечества — их утрата равносильна утрате самой культуры."],
quote:{text:"Не обязательно сжигать книги, чтобы уничтожить культуру. Просто заставьте людей перестать ______.",answer:"читать"},
keyFacts:[{q:"Чем занимаются пожарные в мире романа?",a:"Сжигают запрещённые книги вместо тушения пожаров",distractors:["Тушат обычные пожары","Охраняют библиотеки","Печатают книги"]},{q:"Кто пробуждает в Монтэге способность думать?",a:"Юная соседка Кларисса",distractors:["Его жена Милдред","Начальник пожарной части","Случайный незнакомец в метро"]}],
tip:"Мнемоника: «451 градус — градус безмыслия» (без книг общество превращается в толпу)."},

{id:15,title:"Вельд",author:"Р. Брэдбери",pages:"~15 стр.",adaptation:"Нет широко известной",tags:["технологии","семья","предупреждение"],
summary:"В «умном доме» будущего детская комната-симулятор по желанию детей превращается в африканскую саванну с настоящими львами. Родители, встревоженные одержимостью детей этой комнатой, решают её отключить — и дети запирают их внутри, где львы убивают взрослых.",
characters:[{name:"Питер и Венди",desc:"дети, полностью зависимые от виртуальной реальности детской"},{name:"Джордж и Лидия Хедли",desc:"родители, слишком поздно осознающие опасность технологий"}],
arguments:["Чрезмерное увлечение технологиями заменяет живое общение в семье и разрушает связь родителей и детей.","Потакание всем желаниям ребёнка без ограничений опасно для его нравственного развития.","Технологии, лишённые контроля, могут выйти из-под власти человека и обратиться против него.","Автор предупреждает: удобство и комфорт не должны заменять родительское воспитание и внимание."],
quote:{text:"Детская комната должна была быть местом для игры, а стала местом их подлинных ______.",answer:"желаний"},
keyFacts:[{q:"Во что превращается детская комната по желанию детей?",a:"В африканскую саванну с настоящими хищными львами",distractors:["В джунгли без животных","В школьный класс","В пустой белый экран"]},{q:"Что происходит с родителями в финале?",a:"Дети запирают их в комнате, и львы их убивают",distractors:["Родители отключают комнату и всё заканчивается благополучно","Родители уезжают жить отдельно","Дети раскаиваются и просят прощения"]}],
tip:"Мнемоника: «Вельд — велит дому вредить» (техника без контроля родителей опасна)."},

{id:16,title:"Последний лист",author:"О. Генри",pages:"~10 стр.",adaptation:"Нет широко известной",tags:["самопожертвование","искусство","надежда"],
summary:"Тяжело больная художница Джонси решила, что умрёт, когда с дикого винограда за окном упадёт последний лист. Старый неудачливый художник Берман в бурную ночь тайно рисует на стене лист вместо настоящего, спасая веру Джонси в жизнь, но сам умирает от простуды — этот лист становится его истинным шедевром.",
characters:[{name:"Джонси",desc:"больная художница, потерявшая волю к жизни"},{name:"Берман",desc:"старый художник-неудачник, ценой жизни создающий главный шедевр"},{name:"Сью",desc:"подруга Джонси, заботящаяся о ней"}],
arguments:["Самопожертвование ради спасения другого человека — высшее проявление любви к ближнему.","Истинное искусство не то, что приносит славу, а то, что спасает жизнь.","Вера в жизнь и надежда способны буквально удержать человека на грани.","Настоящий шедевр может остаться незамеченным при жизни творца, но спасти чью-то судьбу."],
quote:{text:"Это был шедевр Бермана — он написал его в ту ночь, когда упал ______ лист.",answer:"последний"},
keyFacts:[{q:"Почему умирает Берман?",a:"Простужается, рисуя лист на стене под дождём",distractors:["Он был уже смертельно болен изначально","Погибает от несчастного случая","Умирает от старости своей смертью"]},{q:"Что спасает Джонси от смерти?",a:"Вера, что настоящий лист так и не упал",distractors:["Новое лекарство","Переезд в другой город","Помощь врача"]}],
tip:"Мнемоника: «Последний лист — жизнь дал» (искусство ценой жизни спасает жизнь)."},

{id:17,title:"Дары волхвов",author:"О. Генри",pages:"~8 стр.",adaptation:"Нет широко известной",tags:["любовь","жертва","семья"],
summary:"Бедная молодая пара, Делла и Джим, хочет сделать друг другу рождественские подарки. Делла продаёт свои прекрасные волосы, чтобы купить цепочку для часов мужа, а Джим продаёт часы, чтобы купить гребни для её волос. Подарки оказываются «бесполезны», но становятся доказательством настоящей любви.",
characters:[{name:"Делла",desc:"жена, жертвующая волосами ради подарка мужу"},{name:"Джим",desc:"муж, продающий фамильные часы ради подарка жене"}],
arguments:["Истинная любовь измеряется готовностью жертвовать самым дорогим ради другого.","Ценность подарка не в деньгах, а в вложенной в него любви и самоотречении.","Взаимная жертва, даже «напрасная» с практической точки зрения, сближает людей сильнее любых вещей.","Автор иронично сравнивает пару с волхвами — их дары так же мудры, как дары библейских волхвов."],
quote:{text:"Из всех дарителей эти двое были самыми ______, ибо отдали самое дорогое, что имели.",answer:"мудрыми"},
keyFacts:[{q:"Что продаёт Делла ради подарка Джиму?",a:"Свои волосы",distractors:["Обручальное кольцо","Мебель","Свою одежду"]},{q:"Почему подарки в итоге оказываются «бесполезны»?",a:"Джим продал часы, к которым Делла купила цепочку, а Делла остригла волосы, для которых Джим купил гребни",distractors:["Подарки потерялись по дороге домой","Магазин обманул обоих","Подарки просто не понравились"]}],
tip:"Мнемоника: «Дары волхвов — дарить с толком» (жертва ради любви ценнее самой вещи)."},

{id:18,title:"Господин из Сан-Франциско",author:"И. Бунин",pages:"~20 стр.",adaptation:"Нет широко известной",tags:["смерть","богатство","общество"],
summary:"Богатый безымянный американец отправляется в роскошное путешествие в Европу, уверенный, что деньги дают ему власть над жизнью. Он внезапно умирает на острове Капри, и его тело везут обратно на родину в трюме того же корабля, в грузовом ящике из-под содовой — символ равенства всех перед смертью.",
characters:[{name:"Господин из Сан-Франциско",desc:"безымянный богач, воплощение слепой веры в силу денег"},{name:"Пассажиры корабля «Атлантида»",desc:"светское общество, живущее напоказ, в фальши и роскоши"}],
arguments:["Смерть уравнивает всех, независимо от богатства и социального статуса.","Слепая вера в силу денег и статуса обнажает внутреннюю пустоту человека.","Внешний блеск светского общества скрывает духовную пустоту и фальшь.","Автор осуждает бездуховную, потребительскую жизнь ради самой жизни, без цели и смысла."],
quote:{text:"Имени этого господина ни в Неаполе, ни на Капри никто не ______.",answer:"запомнил"},
keyFacts:[{q:"Почему у главного героя нет имени в рассказе?",a:"Это подчёркивает его безликость — он лишь символ богатства, а не личность",distractors:["Автор просто забыл его указать","Герой скрывает своё имя специально","Имя было утеряно при переводе"]},{q:"Как везут тело господина домой?",a:"В грузовом трюме, в ящике из-под содовой воды",distractors:["В роскошном гробу в каюте первого класса","Тело оставляют на Капри","Специальным отдельным рейсом"]}],
tip:"Мнемоника: «Господин из Сан-Франциско — сгинул без чина» (богатство не спасает от смерти)."},

{id:19,title:"Чистый понедельник",author:"И. Бунин",pages:"~15 стр.",adaptation:"Нет широко известной",tags:["любовь","духовность","выбор"],
summary:"Рассказчик влюблён в загадочную красивую девушку, которая ведёт светскую жизнь, но тайно посещает церкви и монастыри. В Чистый понедельник, после последней ночи вместе, она неожиданно уходит в монастырь, выбрав духовный путь вместо земной любви.",
characters:[{name:"Рассказчик",desc:"влюблённый молодой человек, не понимающий внутреннего мира героини"},{name:"Она (героиня)",desc:"загадочная девушка, разрывающаяся между земной жизнью и духовным поиском"}],
arguments:["Духовный поиск иногда оказывается сильнее земной любви и привычной жизни.","Загадочность русской души — способность к внезапному, необратимому нравственному выбору.","Настоящая любовь не всегда означает обладание — герой должен принять уход возлюбленной.","Тема противопоставления телесного и духовного начала в человеке."],
quote:{text:"Нет, замуж я не могу... я ______ в монастырь, — сказала она тихо.",answer:"уйду"},
keyFacts:[{q:"Куда уходит героиня в финале рассказа?",a:"В монастырь",distractors:["За границу","К другому мужчине","Возвращается к родителям"]},{q:"Что символизирует название «Чистый понедельник»?",a:"Первый день Великого поста — начало духовного очищения и отказа от мирского",distractors:["Просто день недели без особого смысла","День их свадьбы","День расставания без религиозного подтекста"]}],
tip:"Мнемоника: «Чистый понедельник — чистый выбор души» (духовное побеждает земное)."},

{id:20,title:"Безумная Евдокия",author:"А. Алексин",pages:"~50 стр.",adaptation:"Нет широко известной",tags:["семья","эгоизм","воспитание"],
summary:"Родители считают дочь Олю исключительной и во всём её поддерживают, не замечая растущего эгоизма. Классная руководительница Евдокия Савельевна, которую родители называют «безумной» за строгость, пытается учить детей человечности. Во время похода Оля уходит одна, не предупредив никого, ради собственного «триумфа» — начинаются масштабные поиски, и мать Оли от потрясения теряет рассудок.",
characters:[{name:"Оля",desc:"одарённая, но эгоистичная девочка, привыкшая быть в центре внимания"},{name:"Отец (рассказчик)",desc:"любящий родитель, слишком поздно замечающий ошибки воспитания"},{name:"Мама Оли",desc:"женщина с больным сердцем, теряющая рассудок от потрясения"},{name:"Евдокия Савельевна",desc:"учительница, которую считают «безумной» за то, что воспитывает не только успех, но и человечность"}],
arguments:["Талант не оправдывает эгоизма — способности не заменяют умения считаться с другими.","Слепая родительская любовь, поощряющая только успех, опасна — путает воспитание с восхищением.","Учитель — нравственный ориентир, который видит дальше сиюминутных успехов ученика.","Один эгоистичный поступок способен обернуться настоящей трагедией для близких.","Прозрение через беду: отец осознаёт ошибку воспитания только после катастрофы."],
quote:{text:"Жить только собой — это полбеды. Гораздо страшнее, живя только собой, затрагивать походя и чужие ______.",answer:"судьбы"},
keyFacts:[{q:"Почему родители называют Евдокию Савельевну «безумной»?",a:"Потому что она не восхищается исключительностью Оли и воспитывает в детях человечность, а не культ успеха",distractors:["Она была психически нездорова","Она плохо преподавала свой предмет","Она была слишком молода для профессии"]},{q:"Что происходит с мамой Оли после похода?",a:"От потрясения ложным известием о гибели дочери она теряет рассудок",distractors:["Она уезжает жить к родственникам","Она мирится с Евдокией Савельевной и всё заканчивается хорошо","Она увольняет учительницу"]}],
tip:"Мнемоника: «Безумная Евдокия — безумие эгоизма» (не учительница безумна, а поощряемый эгоизм)."},

{id:21,title:"Матрёнин двор",author:"А. Солженицын",pages:"~40 стр.",adaptation:"Нет широко известной",tags:["праведник","жертвенность","деревня"],
summary:"Рассказчик поселяется у одинокой пожилой крестьянки Матрёны, всю жизнь помогавшей всем бескорыстно, несмотря на собственную бедность. Она погибает, помогая родственникам перевозить часть своего дома (горницу) через железнодорожный переезд — только после смерти окружающие понимают, каким праведным человеком она была, хотя при жизни её считали чудачкой.",
characters:[{name:"Матрёна",desc:"бескорыстная праведница, помогающая всем, несмотря на нищету"},{name:"Рассказчик (Игнатич)",desc:"постоялец, постепенно понимающий истинную ценность Матрёны"},{name:"Фаддей",desc:"родственник, чья жадность косвенно приводит к гибели Матрёны"}],
arguments:["«Не стоит село без праведника» — на таких бескорыстных людях, как Матрёна, держится весь мир.","Истинную ценность человека часто замечают только после его смерти.","Жадность и материальные интересы (спор о горнице) разрушают то доброе, что создавала Матрёна.","Праведность не требует наград и признания — она в ежедневной готовности помогать другим."],
quote:{text:"Все мы жили рядом с ней и не поняли, что есть она тот самый ______, без которого не стоит село.",answer:"праведник"},
keyFacts:[{q:"Как погибает Матрёна?",a:"Попадает под поезд, помогая перевозить часть своего дома через переезд",distractors:["Умирает от старости","Погибает в пожаре","Тонет в реке"]},{q:"Как относились к Матрёне соседи при её жизни?",a:"Считали чудачкой, пользовались её бескорыстной помощью, не ценя её",distractors:["Все безмерно уважали её","Её боялись","Она была самой богатой в деревне"]}],
tip:"Мнемоника: «Матрёнин двор — держит мир» (праведник незаметен, но на нём всё держится)."},

{id:22,title:"Прощание с Матёрой",author:"В. Распутин",pages:"~180 стр.",adaptation:"Да, фильм «Прощание» 1981 г.",tags:["традиции","экология","память"],
summary:"Остров-деревню Матёру должны затопить ради строительства ГЭС. Старуха Дарья и другие пожилые жители не могут смириться с потерей родной земли, могил предков и векового уклада, в то время как молодое поколение легко принимает переезд и прогресс.",
characters:[{name:"Дарья",desc:"пожилая жительница, хранительница памяти и традиций острова"},{name:"Павел",desc:"сын Дарьи, разрывающийся между старым укладом и новой жизнью"},{name:"Молодёжь деревни",desc:"легко расстаётся с корнями ради удобств нового мира"}],
arguments:["Конфликт прогресса и традиции: технический прогресс часто уничтожает духовные и культурные корни.","Память о предках и родной земле — основа нравственной устойчивости человека.","Утрата малой родины — это утрата части себя, даже если взамен предлагается комфорт.","Автор предупреждает об экологической и духовной цене бездумного «покорения природы»."],
quote:{text:"Разве это ничего не стоит — своя ______, где каждая тропка знакома?",answer:"земля"},
keyFacts:[{q:"Почему должна исчезнуть деревня Матёра?",a:"Остров будет затоплен из-за строительства гидроэлектростанции",distractors:["Деревня сгорела","Жители сами решили переехать","Началась эпидемия"]},{q:"Как относится старшее поколение к переезду?",a:"Тяжело переживает потерю родной земли и могил предков",distractors:["Радуется новым квартирам","Полностью равнодушно","Уезжает первыми, не оглядываясь"]}],
tip:"Мнемоника: «Прощание с Матёрой — прощание с корнями» (прогресс против памяти предков)."},

{id:23,title:"Уроки французского",author:"В. Распутин",pages:"~25 стр.",adaptation:"Да, фильм 1978 г.",tags:["доброта","учитель","бедность"],
summary:"Голодающий мальчик из деревни, живущий у чужих людей ради учёбы, начинает играть на деньги, чтобы купить еду. Учительница французского Лидия Михайловна, узнав о его нужде, начинает тайно играть с ним на деньги, поддавая ему выигрывать, за что её увольняют — но она успевает помочь мальчику выжить.",
characters:[{name:"Мальчик-рассказчик",desc:"голодающий, но гордый ученик, вынужденный играть на деньги ради еды"},{name:"Лидия Михайловна",desc:"учительница, идущая на риск карьерой ради помощи ученику"}],
arguments:["Настоящая педагогика выходит за рамки формальных правил, если речь о спасении ребёнка.","Доброта учителя способна изменить судьбу ученика сильнее любых уроков по предмету.","Гордость и достоинство важны даже в нищете — мальчик не берёт помощь напрямую.","Автор показывает цену человечности: Лидия Михайловна жертвует работой ради ученика."],
quote:{text:"Я и после её отъезда получал ______ — то присланные ей яблоки, то макароны.",answer:"посылки"},
keyFacts:[{q:"Почему учительница играет с мальчиком в азартную игру на деньги?",a:"Чтобы он мог выигрывать деньги на еду, не чувствуя себя облагодетельствованным",distractors:["Ей просто нравилось играть","Чтобы наказать его","По просьбе директора школы"]},{q:"Чем заканчивается история для Лидии Михайловны?",a:"Её увольняют из школы за игру с учеником на деньги",distractors:["Её повышают","Она ничего не теряет","Она сама увольняется без причины"]}],
tip:"Мнемоника: «Уроки французского — уроки человечности» (главный урок был не по предмету)."},

{id:24,title:"Портрет",author:"Н. Гоголь",pages:"~50 стр.",adaptation:"Нет широко известной",tags:["искусство","деньги","мораль"],
summary:"Бедный талантливый художник Чартков находит таинственный портрет ростовщика с живыми, пугающими глазами, из рамы которого выпадают золотые монеты. Разбогатев, Чартков продаёт свой дар за модную, коммерческую живопись на заказ, теряет истинный талант и, осознав это слишком поздно, впадает в безумие, уничтожая произведения искусства.",
characters:[{name:"Чартков",desc:"талантливый художник, продавший дар ради денег и славы"},{name:"Ростовщик",desc:"загадочный персонаж портрета, символ дьявольского искушения деньгами"}],
arguments:["Погоня за лёгкими деньгами разрушает истинный талант и творческую честность.","Настоящее искусство требует труда и духовной работы, а не удовлетворения моды и заказчика.","Деньги, полученные нечестным или мистическим путём, приносят не счастье, а гибель.","Автор предостерегает: продажа таланта ради выгоды оборачивается моральной деградацией."],
quote:{text:"Талант его исчез ______, а деньги, добытые нечестно, не принесли счастья.",answer:"безвозвратно"},
keyFacts:[{q:"Что находит Чартков в старом портрете?",a:"Спрятанные золотые монеты",distractors:["Письмо от художника","Драгоценные камни","Ничего, портрет был обычным"]},{q:"Что происходит с талантом Чарткова после того, как он разбогател?",a:"Он теряет истинный дар, рисуя лишь модные заказные портреты",distractors:["Талант становится ещё сильнее","Он бросает живопись полностью и сразу","Он становится величайшим художником своего века"]}],
tip:"Мнемоника: «Портрет — портит талант» (лёгкие деньги губят настоящее искусство)."},

{id:25,title:"В аптеке",author:"А. Чехов",pages:"~5 стр.",adaptation:"Нет широко известной",tags:["маленький человек","равнодушие","бедность"],
summary:"Больной учитель Свойкин приходит в аптеку за лекарством поздно ночью, но ему не хватает нескольких копеек. Равнодушный провизор отказывается сделать скидку или войти в положение, несмотря на явную нужду и болезнь клиента — маленькая деталь показывает бездушие городской системы к простому человеку.",
characters:[{name:"Свойкин",desc:"больной учитель, униженный нехваткой нескольких копеек"},{name:"Провизор",desc:"равнодушный аптечный работник, символ бюрократического бездушия"}],
arguments:["Равнодушие к чужой беде проявляется даже в мелочах — не обязательно в крупных трагедиях.","Тема «маленького человека», униженного системой, актуальна и в бытовых, не только трагических ситуациях.","Автор высмеивает бездушный формализм, ставящий правила выше сострадания к человеку.","Мелкая деталь (нехватка нескольких копеек) обнажает крупную социальную проблему безразличия."],
quote:{text:"Не хватает нескольких ______, а лекарство необходимо сейчас же.",answer:"копеек"},
keyFacts:[{q:"Почему Свойкин не может купить лекарство?",a:"Ему не хватает нескольких копеек, а провизор отказывается пойти навстречу",distractors:["Лекарства не было в наличии","Аптека была закрыта","Ему не выписали рецепт"]},{q:"Как ведёт себя провизор?",a:"Равнодушно и формально, не сочувствуя больному человеку",distractors:["Даёт лекарство бесплатно","Вызывает скорую помощь","Уговаривает Свойкина занять денег у соседей"]}],
tip:"Мнемоника: «В аптеке — в апатии» (равнодушие ранит не меньше трагедии)."},

{id:26,title:"Завтра была война",author:"Б. Васильев",pages:"~90 стр.",adaptation:"Да, фильм 1987 г.",tags:["репрессии","дружба","взросление"],
summary:"Накануне Великой Отечественной войны школьница Вика Люберецкая переживает арест отца как «врага народа». Несмотря на давление и осуждение, класс во главе с Искрой Поляковой поддерживает Вику. После самоубийства Вики от отчаяния и позора весь класс, рискуя будущим, приходит на её похороны вопреки запрету властей.",
characters:[{name:"Искра Полякова",desc:"принципиальная активная школьница, лидер класса"},{name:"Вика Люберецкая",desc:"дочь «врага народа», не выдержавшая травли и позора"},{name:"Класс 9-Б",desc:"коллектив, проявляющий солидарность вопреки страху репрессий"}],
arguments:["Дружба и солидарность способны противостоять давлению системы даже в самые страшные времена.","Репрессии калечат не только осуждённых, но и их детей, ломая юные судьбы.","Нравственный выбор ребят прийти на похороны Вики — акт настоящего гражданского мужества.","Довоенное поколение взрослело быстро, сталкиваясь с несправедливостью взрослого мира."],
quote:{text:"Весь класс пришёл на похороны, хотя это было ______ и грозило исключением.",answer:"запрещено"},
keyFacts:[{q:"Почему Вика Люберецкая оказывается в опасности?",a:"Её отца арестовывают как «врага народа»",distractors:["Она сама совершила преступление","Она поссорилась с одноклассниками","Началась война и её эвакуировали"]},{q:"Как класс реагирует на трагедию Вики?",a:"Несмотря на запрет, весь класс приходит на её похороны",distractors:["Все отворачиваются от неё из страха","Класс расформировывают","Никто не узнаёт о случившемся"]}],
tip:"Мнемоника: «Завтра была война — сегодня было мужество» (дружба сильнее страха)."},

{id:27,title:"Не стреляйте в белых лебедей",author:"Б. Васильев",pages:"~200 стр.",adaptation:"Да, фильм 1980 г.",tags:["природа","доброта","конфликт"],
summary:"Простодушный и добрый лесник Егор Полушкин, которого все считают неудачником и «чудаком», искренне любит природу и охраняет лебедей на озере от браконьеров. Он погибает, защищая птиц от жестоких браконьеров, среди которых оказывается и его собственный сын.",
characters:[{name:"Егор Полушкин",desc:"добрый чудаковатый лесник, живущий в гармонии с природой"},{name:"Харитина (жена)",desc:"верная жена, поддерживающая Егора несмотря на насмешки соседей"},{name:"Браконьеры",desc:"воплощение жестокости и потребительского отношения к природе"}],
arguments:["Гармония с природой требует не выгоды, а бескорыстной любви и заботы, как у Егора.","«Чудаки», которых не понимает общество, часто оказываются его нравственным ориентиром.","Жестокое, потребительское отношение к природе разрушает и природу, и самого человека.","Цена защиты природы и справедливости иногда — собственная жизнь."],
quote:{text:"Не стреляйте в белых ______, — это всё, что успел крикнуть Егор.",answer:"лебедей"},
keyFacts:[{q:"Кого защищает Егор Полушкин ценой своей жизни?",a:"Лебедей от браконьеров",distractors:["Собственный дом от пожара","Деревню от наводнения","Жену от нападавших"]},{q:"Как относятся соседи к Егору при его жизни?",a:"Считают его чудаком и неудачником",distractors:["Все его глубоко уважают","Его боятся","Он самый богатый в деревне"]}],
tip:"Мнемоника: «Не стреляйте в лебедей — не убивайте доброту» (чудак = совесть деревни)."},

{id:28,title:"Вам и не снилось",author:"Г. Щербакова",pages:"~90 стр.",adaptation:"Да, фильм 1980 г.",tags:["любовь","семья","конфликт поколений"],
summary:"Школьники Роман и Юля переживают первую настоящую любовь, но сталкиваются с яростным сопротивлением матери Романа, которая всеми способами пытается разлучить их, считая чувства детей несерьёзными. Конфликт достигает кульминации, когда Роман, пытаясь увидеть Юлю, срывается с окна и оказывается на грани жизни и смерти.",
characters:[{name:"Роман",desc:"влюблённый подросток, готовый на всё ради чувства"},{name:"Юля",desc:"возлюбленная Романа, страдающая от вмешательства взрослых"},{name:"Мать Романа",desc:"воплощение родительского эгоизма и непонимания чувств детей"}],
arguments:["Взрослые часто недооценивают силу и серьёзность первой юношеской любви.","Вмешательство родителей из благих побуждений может привести к трагическим последствиям.","Конфликт поколений обнажает разницу между «правильной» жизнью по мнению взрослых и настоящими чувствами детей.","Название иронично напоминает взрослым: подлинные чувства детей им действительно «и не снились»."],
quote:{text:"Вам, взрослым, такое даже не могло ______, — думала Юля.",answer:"присниться"},
keyFacts:[{q:"Кто мешает отношениям Романа и Юли?",a:"Мать Романа, не признающая их чувства серьёзными",distractors:["Учителя школы","Друзья Романа","Сама Юля передумывает"]},{q:"Что происходит с Романом в кульминации?",a:"Он срывается с окна, пытаясь увидеть Юлю, и оказывается на грани жизни и смерти",distractors:["Он уезжает в другой город","Он мирится с матерью и всё заканчивается спокойно","Ничего серьёзного не происходит"]}],
tip:"Мнемоника: «Вам и не снилось — взрослым не понять» (юная любовь недооценена взрослыми)."},

{id:29,title:"Сашка",author:"В. Кондратьев",pages:"~90 стр.",adaptation:"Да, фильм 1981 г.",tags:["война","гуманизм","милосердие"],
summary:"Молодой солдат Сашка на фронте под Ржевом берёт в плен немецкого солдата. Несмотря на приказ командира расстрелять пленного в отместку за погибших товарищей, Сашка отказывается убивать безоружного человека, сохраняя человечность даже в условиях жестокой войны.",
characters:[{name:"Сашка",desc:"простой солдат, сохраняющий милосердие и человечность на войне"},{name:"Пленный немец",desc:"безоружный враг, чью жизнь спасает отказ Сашки стрелять"}],
arguments:["Настоящий гуманизм проявляется именно тогда, когда его труднее всего проявить — на войне, к врагу.","Приказ не может быть выше человеческой совести — Сашка ослушивается ради нравственного принципа.","Война испытывает человека, но не всех превращает в жестоких — герой сохраняет достоинство.","Милосердие к побеждённому врагу — признак настоящей силы, а не слабости."],
quote:{text:"Не могу я его, безоружного, ______, — сказал Сашка командиру.",answer:"убить"},
keyFacts:[{q:"Какой приказ получает Сашка?",a:"Расстрелять пленного немецкого солдата",distractors:["Отпустить пленного самостоятельно","Допросить пленного и отпустить","Передать пленного в штаб немедленно"]},{q:"Как поступает Сашка?",a:"Отказывается расстреливать безоружного пленного",distractors:["Выполняет приказ без раздумий","Расстреливает пленного, но потом жалеет","Пленный убегает сам"]}],
tip:"Мнемоника: «Сашка — совесть солдата» (гуманизм сильнее приказа)."},

{id:30,title:"Герой нашего времени",author:"М. Лермонтов",pages:"~180 стр.",adaptation:"Да, несколько экранизаций",tags:["лишний человек","эгоизм","судьба"],
summary:"Роман состоит из нескольких новелл о Григории Печорине — умном, талантливом, но глубоко разочарованном и эгоистичном офицере, который от скуки разрушает судьбы окружающих (Бэлы, княжны Мери, контрабандистов), не находя смысла в собственной жизни. Печорин — классический тип «лишнего человека» эпохи.",
characters:[{name:"Печорин",desc:"главный герой, «лишний человек», разрушающий судьбы окружающих от скуки"},{name:"Бэла",desc:"похищенная Печориным горянка, гибнущая из-за его эгоизма"},{name:"Максим Максимыч",desc:"простодушный офицер, искренне привязанный к Печорину"},{name:"Княжна Мери",desc:"девушка, чьи чувства Печорин цинично использует ради развлечения"}],
arguments:["Эгоизм и скука одарённого человека без цели в жизни разрушительны для окружающих.","Тип «лишнего человека» — трагедия целого поколения, не находящего применения своим силам.","Печорин ищет смысл жизни через испытание чужих судеб, но сам остаётся несчастен.","Роман поднимает вопрос ответственности личности за причинённую другим боль, даже без злого умысла."],
quote:{text:"Из двух друзей всегда один является ______ другого.",answer:"рабом"},
keyFacts:[{q:"Как называется тип героя, к которому относится Печорин?",a:"«Лишний человек»",distractors:["«Маленький человек»","«Новый человек»","«Естественный человек»"]},{q:"Что происходит с Бэлой из-за Печорина?",a:"Она погибает, полюбив и будучи брошенной Печориным",distractors:["Она выходит замуж за Печорина и живёт счастливо","Она возвращается к своей семье невредимой","Печорин спасает её от опасности"]}],
tip:"Мнемоника: «Герой нашего времени — герой без применения» (сила без цели разрушает)."}
];

const RULES = [
{id:1,category:"orfo",task:"№9",title:"Чередующиеся гласные в корне",
explanation:"В корнях с чередованием гласная зависит не от ударения, а от условий: наличия суффикса -А- после корня (-бир-/-бер-, -тир-/-тер-, -мир-/-мер- и т.п.), от согласной в корне (-раст-/-рос-, -лаг-/-лож-, -кас-/-кос-), от значения (-мак-/-мок-, -равн-/-ровн-) или от ударения (-гар-/-гор-, -зар-/-зор-, -плав-/-плов-).",
examples:["соб<b>и</b>рать — соб<b>е</b>ру (суффикс -а-)","р<b>а</b>стение — искл. отр<b>о</b>сль, Р<b>о</b>стов","заг<b>о</b>реть — з<b>а</b>рево (без ударения — о, кроме искл.)","м<b>а</b>кать в жидкость — пром<b>о</b>кнуть под дождём"],
mcq:[{q:"В каком слове пропущена буква А?",options:["предл..жить","р..стение","к..снуться","заг..рать"],answer:"к..снуться",hint:"кас-/кос-: перед суффиксом -а- пишем А"},
{q:"В каком ряду во всех словах пропущена одна и та же буква?",options:["распол..жение, приг..рать, заг..реть","выр..сти, р..стительность, Р..стов","з..ря, ср..внение, оз..рять","соб..ру, бл..стеть, ум..реть"],answer:"з..ря, ср..внение, оз..рять",hint:"без ударения в -зар-/-зор- пишется А"}],
fillblank:[{text:"Он бережно к..снулся руки друга.",answer:"о",hint:"кас-/кос-: нет суффикса -а- после корня → О (коснуться)"},
{text:"Растение выр..сло у самой дороги.",answer:"о",hint:"-рос-/-раст-: перед С (без Т) пишем О, искл. Ростов, ростовщик, отрасль"}]},

{id:2,category:"orfo",task:"№10",title:"Правописание приставок",
explanation:"Приставки на -З/-С зависят от звонкости следующего согласного (безграничный — бесконечный). ПРЕ- пишется в значении «очень» и «пере-» (превеликий, преступить), ПРИ- — в значении приближения, присоединения, неполноты действия (прибежать, пришить, приоткрыть). Есть слова, где значение приставки уже не осознаётся и написание нужно запомнить (президент, привилегия, приключение).",
examples:["бе<b>з</b>граничный — бе<b>с</b>компромиссный","пр<b>е</b>градить (=пере-)","пр<b>и</b>открыть (неполнота действия)","пр<b>и</b>вилегия (искл., запомнить)"],
mcq:[{q:"В каком слове пропущена буква З?",options:["бе..вкусный","и..чезнуть","ра..писание","бе..хитростный"],answer:"бе..вкусный",hint:"перед звонким В пишем З"},
{q:"В каком слове пишется ПРИ-?",options:["пр..увеличить","пр..открыть дверь","пр..градить путь","пр..небречь"],answer:"пр..открыть дверь",hint:"неполнота действия"}],
fillblank:[{text:"Пр..морский город расположен у самого берега.",answer:"и",hint:"близость к чему-либо — ПРИ-"},
{text:"Она пр..небрегла всеми советами.",answer:"е",hint:"пренебречь = «пере-», значение исключения из правил — запомнить: ПРЕ-"}]},

{id:3,category:"orfo",task:"№11",title:"Суффиксы разных частей речи",
explanation:"В суффиксах существительных и прилагательных гласная часто зависит от ударения или от суффикса производящего слова: -ЕК-/-ИК- (если при склонении гласная выпадает — ЕК: замочек-замочка, если нет — ИК: ключик-ключика). Суффиксы -ЕВА-/-ОВА- у глаголов пишутся, если в 1 л. ед.ч. слово заканчивается на -ую/-юю (командовать — командую).",
examples:["ключ<b>и</b>к — ключ<b>и</b>ка (гласная не выпадает)","замоч<b>е</b>к — замоч<b>к</b>а (гласная выпадает)","команд<b>ова</b>ть — команд<b>у</b>ю","совет<b>ова</b>ть — совет<b>у</b>ю"],
mcq:[{q:"В каком слове пишется суффикс -ИК-?",options:["горош..к","стол..к","дожд..к","овраж..к"],answer:"дожд..к",hint:"дождик — дождика, гласная сохраняется"},
{q:"Укажите слово с суффиксом -ЕВА-",options:["раскач..вать","испыт..вать","затраг..вать","бесед..вать"],answer:"бесед..вать",hint:"беседую → -ева- (беседовать)"}],
fillblank:[{text:"Он постоянно расспраш..вал соседей о новостях.",answer:"и",hint:"расспрашиваю → суффикс -ива-"},
{text:"Врач осматр..вал пациента внимательно.",answer:"и",hint:"осматриваю → -ива-"}]},

{id:4,category:"orfo",task:"№12",title:"Окончания глаголов и суффиксы причастий",
explanation:"Личные окончания глаголов зависят от спряжения: I спряжение — Е, У/Ю (пишет, пишут); II спряжение — И, А/Я (говорит, говорят). Ко II спряжению относятся глаголы на -ить (кроме брить, стелить) и 11 глаголов-исключений (гнать, держать, смотреть, видеть, дышать, слышать, ненавидеть, зависеть, терпеть, вертеть, обидеть). Суффиксы причастий также зависят от спряжения производящего глагола: -ущ/-ющ (I спр.), -ащ/-ящ (II спр.).",
examples:["он бор<b>е</b>тся (I спр., искл. в наст.)","он дыш<b>и</b>т (II спр., искл.)","стро<b>ящ</b>ий дом (II спр. — строить)","та<b>ющ</b>ий снег (I спр. — таять)"],
mcq:[{q:"В каком слове пропущена буква Е?",options:["они бор..тся","они кле..т","они стел..т","они держ..т"],answer:"они бор..тся",hint:"бороться — I спряжение, искл."},
{q:"Укажите слово с буквой Я в суффиксе причастия",options:["кол..щий","стро..щий","бор..щийся","пиш..щий"],answer:"стро..щий",hint:"строить — II спряжение → -ящ-"}],
fillblank:[{text:"Дети, дыш..щие свежим воздухом, бежали по полю.",answer:"а",hint:"дышать — искл. II спряжения → -ащ-"},
{text:"Она вид..т вдалеке дым.",answer:"и",hint:"видеть — искл. II спряжения"}]},

{id:5,category:"orfo",task:"№13",title:"НЕ и НИ с разными частями речи",
explanation:"НЕ пишется слитно, если слово не употребляется без НЕ, при образовании нового слова (недруг=враг), с причастиями без зависимых слов и противопоставления. Раздельно — с глаголами, деепричастиями, при наличии противопоставления с союзом А, с краткими причастиями, при наличии слов «далеко не», «отнюдь не». НИ используется для усиления отрицания и в устойчивых оборотах (никто, ни разу, во что бы то ни стало).",
examples:["<b>не</b>годовать (без не не употр.)","отнюдь <b>не</b> лёгкий путь","<b>не</b> прочитанная мной книга (есть завис. слово)","куда бы он <b>ни</b> пошёл (усиление)"],
mcq:[{q:"В каком варианте НЕ пишется слитно?",options:["(не)прочитанная книга, а начатая","(не)годуя от возмущения","ничуть (не)интересный фильм","(не)законченный вовремя проект"],answer:"ничуть (не)интересный фильм",hint:"нет зависимых слов и противопоставления → слитно с прилагательным"},
{q:"Где пишется НИ?",options:["Как он н.. старался, ничего не получалось","Он н..когда не опаздывал","Мы н..чего не нашли","Всё верно, кроме первого"],answer:"Как он н.. старался, ничего не получалось",hint:"усилительная частица НИ в придаточном уступки"}],
fillblank:[{text:"Это была далеко н..простая задача.",answer:"е",hint:"«далеко не» — всегда пишется раздельно (частица НЕ)"},
{text:"Кто бы н.. пришёл, дверь была заперта.",answer:"и",hint:"устойчивая конструкция усиления — НИ"}]},

{id:6,category:"orfo",task:"№14",title:"Слитное, дефисное, раздельное написание",
explanation:"Через дефис пишутся сложные прилагательные, образованные от равноправных понятий (юго-западный), наречия с приставкой ПО- и суффиксами -ОМУ/-ЕМУ/-И (по-новому, по-дружески), неопределённые местоимения с -ТО/-ЛИБО/-НИБУДЬ/КОЕ-. Слитно пишутся производные предлоги (вследствие, ввиду), наречия, образованные слиянием предлога и существительного без падежных вопросов (вдалеке). Раздельно — если между частями можно вставить слово или сохраняется падежный вопрос (в течение дня).",
examples:["по-<b>новому</b> взглянуть","кое-<b>кто</b> пришёл","в <b>течение</b> недели (предлог)","в<b>следствие</b> дождя (предлог = из-за)"],
mcq:[{q:"В каком варианте слово пишется через дефис?",options:["(по)этому мосту","сделал (по)новому","(в)следствие опоздания","(в)течение месяца"],answer:"сделал (по)новому",hint:"по- + -ому → дефис"},
{q:"Какое слово пишется слитно?",options:["(в)виду плохой погоды","(в)течение реки","(по)этому вопросу","(из)за угла"],answer:"(в)виду плохой погоды",hint:"ввиду = предлог «из-за» → слитно"}],
fillblank:[{text:"Что[бы] ни случилось, я буду рядом.",answer:"бы",hint:"«что бы ни» в значении уступки — пишется раздельно (что + бы)"},
{text:"Я тоже хочу поехать, и он то[же] хочет.",answer:"же",hint:"тоже = и он (союз) — пишется слитно"}]},

{id:7,category:"orfo",task:"№15",title:"Н и НН в разных частях речи",
explanation:"В прилагательных, образованных от существительных: Н — в суффиксах -АН-/-ЯН-/-ИН- (кожаный, искл. стеклянный, оловянный, деревянный); НН — на стыке основы на Н и суффикса -Н- (сонный), в суффиксах -ОНН-/-ЕНН- (революционный). В причастиях НН пишется, если есть приставка (кроме не-), зависимое слово или слово образовано от глагола совершенного вида (решённый); Н — в отглагольных прилагательных без этих условий (жареная картошка) и в кратких причастиях (задача решена).",
examples:["кожа<b>н</b>ый (искл.-суффикс -ан-)","были<b>нн</b>ый (стык основ)","жаре<b>н</b>ый картофель (без приставки/завис.слова)","зажаре<b>нн</b>ый в масле (есть завис. слово)","задача реше<b>н</b>а (кратк. причастие)"],
mcq:[{q:"В каком слове пишется НН?",options:["были..ая история","серебря..ый браслет","коше..ый луг (сегодня утром)","гуси..ое перо"],answer:"были..ая история",hint:"основа на Н + суффикс Н → были+нн+ая"},
{q:"Где пишется одна Н?",options:["Территория была огражде..а забором","испуга..ый шумом зверь","некоше..ая с весны трава","подкова..ая лошадь"],answer:"Территория была огражде..а забором",hint:"краткое причастие — всегда одна Н"}],
fillblank:[{text:"Штопа..ые мамой носки были ещё тёплыми.",answer:"нн",hint:"есть зависимое слово «мамой» → пишем НН"},
{text:"Дети были очень взволнова..ы новостью.",answer:"н",hint:"краткое причастие → одна Н"}]},

{id:8,category:"punct",task:"№16",title:"Знаки препинания при однородных членах",
explanation:"Между однородными членами без союзов или с союзами А, НО ставится запятая. При повторяющихся союзах И...И, НИ...НИ запятая ставится между всеми однородными членами. Если союз И одиночный — запятая перед ним не нужна. В сложносочинённом предложении с общим союзом И запятая перед И не ставится, если у частей есть общий второстепенный член.",
examples:["Он читал, писал и рисовал.","Не было ни дождя, ни ветра, ни солнца.","В саду цвели розы и пели птицы (общий второст. член — искл.)","Ветер стих, и наступила тишина (ССП, запятая перед И нужна)"],
mcq:[{q:"Где нужна запятая перед И?",options:["Она любит рисовать и петь","Ветер утих и наступила тишина","В доме было тепло и уютно","Мы пили чай и ели пирог"],answer:"Ветер утих и наступила тишина",hint:"это два простых предложения (ССП) — запятая перед И обязательна"},
{q:"Сколько запятых нужно: 'Он не спал ни ночью ни днём ни в дороге'?",options:["1","2","3","0"],answer:"3",hint:"при повторяющемся союзе НИ запятая ставится перед каждым повторением, кроме первого — тут перед каждым НИ, начиная со второго = 3 части, 2 повтора... посчитай внимательно по правилу"}],
fillblank:[{text:"Небо потемнело[,] и хлынул дождь.",answer:",",hint:"ССП — два грамматических центра, запятая перед И нужна"},
{text:"Ни солнца[,] ни звёзд не было видно на небе.",answer:",",hint:"повторяющийся союз НИ...НИ"}]},

{id:9,category:"punct",task:"№17",title:"Обособленные определения и обстоятельства",
explanation:"Причастный оборот обособляется, если стоит после определяемого слова, или перед ним, но имеет добавочное значение причины/уступки, или относится к личному местоимению. Деепричастный оборот обособляется практически всегда, кроме случаев, когда он превратился в устойчивое выражение (сломя голову) или тесно слился со сказуемым по смыслу.",
examples:["Книга, лежащая на столе, была старой (оборот после сл.)","Уставший от работы, он сел отдохнуть (перед личн. мест.)","Мальчик, играя в саду, потерял мяч.","Он бежал сломя голову (устойчивое выражение — без запятой)"],
mcq:[{q:"В каком предложении нужны запятые при причастном обороте?",options:["Лежащая на столе книга была интересной","Книга лежащая на столе была интересной","Она купила лежащую на витрине куклу","Он смотрел на лежащую перед ним карту"],answer:"Книга лежащая на столе была интересной",hint:"оборот стоит после определяемого слова 'книга'"},
{q:"Где деепричастный оборот НЕ обособляется?",options:["Читая книгу, он делал заметки","Спустя рукава он выполнил работу (=небрежно)","Улыбаясь, она подошла ко мне","Заметив ошибку, ученик исправил её"],answer:"Спустя рукава он выполнил работу (=небрежно)",hint:"фразеологизм, не обособляется"}],
fillblank:[{text:"Уставшие после долгого похода[,] туристы быстро уснули.",answer:",",hint:"оборот стоит перед определяемым словом «туристы», но имеет добавочное значение причины — поэтому обособляется"},
{text:"Он шёл[,] не оглядываясь по сторонам.",answer:",",hint:"деепричастный оборот обособляется"}]},

{id:10,category:"punct",task:"№18",title:"Вводные слова и обращения",
explanation:"Вводные слова (конечно, кажется, во-первых, к счастью, таким образом и др.) выделяются запятыми и не являются членами предложения — их можно убрать без потери смысла. Похожие по форме слова могут быть членами предложения (например, «казалось» как сказуемое) — тогда запятая не ставится. Обращения всегда обособляются запятыми независимо от места в предложении.",
examples:["К счастью, дождь скоро закончился.","Он, кажется, опоздал на встречу.","Дорогой друг, я рад тебя видеть.","Дом казался пустым (не вводное — сказуемое, без запятой)"],
mcq:[{q:"В каком предложении есть вводное слово (нужны запятые)?",options:["Дом казался заброшенным","Задача, казалось, была лёгкой","Всё вокруг казалось серым","Небо казалось чистым"],answer:"Задача, казалось, была лёгкой",hint:"здесь 'казалось' можно убрать без потери структуры — вводное"},
{q:"Где нужны запятые при обращении?",options:["Мама я скоро приду","Дорогие друзья приглашаю вас на праздник","Он назвал её мамой","Все ждали маму с работы"],answer:"Дорогие друзья приглашаю вас на праздник",hint:"обращение в начале предложения"}],
fillblank:[{text:"Друзья мои[,] прекрасен наш союз!",answer:",",hint:"обращение"},
{text:"Во-первых[,] нужно всё проверить ещё раз.",answer:",",hint:"вводное слово"}]},

{id:11,category:"punct",task:"№19",title:"Сложноподчинённое предложение",
explanation:"В СПП придаточная часть отделяется запятой от главной. Если придаточное стоит внутри главного, оно выделяется запятыми с двух сторон. При последовательном подчинении нескольких придаточных на стыке союзов (что если, чтобы когда) запятая между ними не ставится, если дальше идёт вторая часть двойного союза (то, так).",
examples:["Я знаю, что ты придёшь.","Дом, который построил дед, стоит до сих пор.","Он сказал, что если будет время, то приедет (двойной союз — без запятой на стыке)","Она молчала, потому что не знала ответа."],
mcq:[{q:"Сколько запятых в предложении: 'Я думаю что если ты постараешься то всё получится'?",options:["1","2","3","0"],answer:"1",hint:"запятая перед 'что', на стыке 'что если' запятой нет из-за 'то' дальше"},
{q:"Где верно расставлены запятые?",options:["Дом который стоит на углу давно продан","Дом, который стоит на углу, давно продан","Дом который, стоит на углу давно, продан","Дом, который стоит, на углу давно продан"],answer:"Дом, который стоит на углу, давно продан",hint:"придаточное внутри главного выделяется с двух сторон"}],
fillblank:[{text:"Я верю[,] что всё будет хорошо.",answer:",",hint:"граница главной и придаточной части"},
{text:"Место, где мы встретились[,] стало особенным.",answer:",",hint:"придаточное стоит внутри главного — закрывающая запятая перед продолжением главной части"}]},

{id:12,category:"punct",task:"№20",title:"Сложное предложение с разными видами связи",
explanation:"В предложениях с сочинительной и подчинительной связью одновременно нужно определить границы каждой части и тип связи между ними. На стыке союзов (и хотя, но если) запятая не ставится, если далее есть вторая часть двойного союза (то, так же).",
examples:["Он замолчал, а она, хотя и была расстроена, попыталась улыбнуться.","Мы вышли на улицу, и, когда дождь закончился, вернулись домой.","Было ясно, что, если он не поторопится, они опоздают."],
mcq:[{q:"Сколько запятых: 'Он знал что если он опоздает то его накажут но всё равно медлил'?",options:["2","3","4","1"],answer:"2",hint:"запятая перед 'что' и перед 'но'; на стыке 'что если' и перед 'то' запятых нет, т.к. есть двойной союз если...то"}],
fillblank:[{text:"Она сказала, что если он придёт[,] она обрадуется.",answer:",",hint:"запятая закрывает придаточное условия 'если он придёт' перед продолжением главной части"}]},

{id:13,category:"punct",task:"№21",title:"Тире и двоеточие в бессоюзном сложном предложении",
explanation:"Двоеточие ставится, если вторая часть поясняет, раскрывает причину или дополняет первую (можно вставить «а именно», «потому что», «что»). Тире ставится, если части противопоставлены, вторая часть содержит вывод/следствие (можно вставить «поэтому»), или указывает на быструю смену событий, время/условие в первой части.",
examples:["Он посмотрел в окно: шёл снег (пояснение = а именно)","Печален я: со мною друга нет (причина = потому что)","Лес рубят — щепки летят (следствие = поэтому)","Сказано — сделано (быстрая смена событий)"],
mcq:[{q:"Где нужно двоеточие?",options:["Я оглянулся ... никого не было (следствие)","Наступила ночь ... стало холодно (следствие)","Одно было ясно ... мы заблудились (пояснение)","Дунул ветер ... лодка перевернулась (быстрая смена)"],answer:"Одно было ясно ... мы заблудились (пояснение)",hint:"вторая часть раскрывает содержание первой = двоеточие"},
{q:"Где нужно тире?",options:["Он знал ... завтра будет трудный день (пояснение)","Собака лает ... караван идёт (противопоставление/следствие)","Мы видели ... лес был вырублен (пояснение)","Радовало одно ... дождь закончился (пояснение)"],answer:"Собака лает ... караван идёт (противопоставление/следствие)",hint:"можно вставить 'но' или понять как противопоставление — тире"}],
fillblank:[{text:"Я доверяю ему полностью[:] он никогда не подводил.",answer:":",hint:"вторая часть = причина (потому что)"},
{text:"Поспешишь[—]людей насмешишь.",answer:"—",hint:"вторая часть = следствие (поэтому)"}]},

{id:14,category:"orfo",task:"№4",title:"Орфоэпические нормы (ударение)",
explanation:"Часть заданий ЕГЭ проверяет знание правильного ударения в словах. Многие слова имеют «ловушки» — распространённые ошибки в постановке ударения. Эти слова нужно запоминать наизусть, так как правил, объясняющих их ударение, как правило, нет — только традиция произношения.",
examples:["звон<b>и́</b>т, звон<b>я́</b>т (не зв<b>о́</b>нит)","крас<b>и́</b>вее (не крас<b>и</b>в<b>е́</b>е)","тор<b>т</b>ы, т<b>о́</b>ртов","б<b>а</b>лов<b>а́</b>ть, изб<b>а</b>лов<b>а́</b>нный","начал<b>а́</b>сь, п<b>о</b>нял<b>а́</b>","кух<b>о́</b>нный","цеп<b>о́</b>чка","ходат<b>а́</b>йство"],
mcq:[{q:"Где верно поставлено ударение?",options:["звОнит","красивЕе","тОрты","баловАть"],answer:"баловАть",hint:"баловАть, избалОванный — ударение на А/О в конце"},
{q:"Где ошибка в ударении?",options:["позвонИшь","углубИть","кухОнный","красивЕе"],answer:"кухОнный",hint:"правильно: кУхонный"}],
fillblank:[{text:"Она пон..ла задачу правильно (ударение на последний слог).",answer:"я",hint:"понялА — ударная гласная А в последнем слоге"},
{text:"Дети весело баловал..сь с щенком (ударение на А).",answer:"и",hint:"баловАлись — ударение на А"}]},

{id:15,category:"orfo",task:"№5",title:"Паронимы",
explanation:"Паронимы — это слова, похожие по звучанию и написанию, но разные по значению (например, ОДЕТЬ и НАДЕТЬ, ЭФФЕКТНЫЙ и ЭФФЕКТИВНЫЙ, ГУМАННЫЙ и ГУМАНИТАРНЫЙ). ОДЕТЬ — кого-то (одеть ребёнка), НАДЕТЬ — что-то на себя (надеть пальто). Важно знать точное значение каждого слова из пары и не путать их в контексте.",
examples:["<b>Надеть</b> пальто, но <b>одеть</b> ребёнка","<b>Эффектный</b> наряд (яркий), <b>эффективный</b> метод (результативный)","<b>Гуманный</b> поступок (человечный), <b>гуманитарная</b> помощь (для людей)","<b>Дипломатичный</b> ответ (тактичный), <b>дипломатический</b> корпус (относящийся к дипломатии)"],
mcq:[{q:"Выберите верный вариант: 'Перед выходом она ___ дочку в тёплую куртку.'",options:["одела","надела","подела","надела бы"],answer:"одела",hint:"одеть — кого-то (дочку)"},
{q:"Выберите верный вариант: 'Новый метод оказался очень ___.'",options:["эффектным","эффективным","эффектированным","эффективированным"],answer:"эффективным",hint:"эффективный = результативный"}],
fillblank:[{text:"Он ___ (надел/одел) шапку и вышел на мороз.",answer:"надел",hint:"надеть — что-то на себя"},
{text:"Врач проявил ___ (гуманное/гуманитарное) отношение к пациенту.",answer:"гуманное",hint:"гуманный = человечный"}]},

{id:16,category:"orfo",task:"№7-8",title:"Грамматические нормы (морфология и синтаксис)",
explanation:"Типичные грамматические ошибки: неправильное построение предложения с деепричастным оборотом (действие деепричастия и сказуемого должно относиться к одному субъекту), нарушение согласования подлежащего и сказуемого, неверное склонение числительных, ошибки в построении предложений с косвенной речью, нарушение управления (уверенность в чём, а не о чём).",
examples:["Подъезжая к станции, у меня слетела шляпа (ошибка — деепричастие относится не к тому лицу)","Он сказал, что он придёт (косв. речь — верно: что придёт)","С пятьюстами рублями (верное склонение числительного)","Уверенность в победе (верное управление, не 'о победе')"],
mcq:[{q:"В каком предложении есть грамматическая ошибка?",options:["Прочитав книгу, я вернул её в библиотеку","Открывая окно, комната наполнилась светом","Заметив ошибку, ученик исправил её","Придя домой, он сразу лёг спать"],answer:"Открывая окно, комната наполнилась светом",hint:"деепричастие 'открывая' должно относиться к лицу, а не к комнате"},
{q:"Какой вариант верный?",options:["Он уверен о своей правоте","Он уверен в своей правоте","Он уверен насчёт своей правоты","Он уверен об своей правоте"],answer:"Он уверен в своей правоте",hint:"управление: уверен В чём"}],
fillblank:[{text:"Согласно ___ (расписание) уроки начинаются в 8:30.",answer:"расписанию",hint:"согласно чему? — дательный падеж"},
{text:"Он рассказал, что ___ (я/он) обязательно вернётся.",answer:"он",hint:"в косвенной речи местоимение меняется на 3-е лицо"}]},

{id:17,category:"gram",task:"№6",title:"Речевые нормы: лишнее слово (плеоназм и тавтология)",
explanation:"Плеоназм — словосочетание, где одно слово дублирует смысл другого (памятный сувенир — сувенир и так «подарок на память»). Тавтология — повтор однокоренных слов (спросить вопрос, случился случай). Плеоназм часто возникает при соединении заимствованного слова с русским того же значения (свободная вакансия, прейскурант цен).",
examples:["памятный сувенир (сувенир = подарок на память)","главная суть (суть уже главное)","свободная вакансия","прейскурант цен","в конечном итоге","коллеги по работе"],
mcq:[{q:"В каком словосочетании есть лишнее слово?",options:["тёплая одежда","памятный сувенир","интересная книга","быстрый бег"],answer:"памятный сувенир",hint:"сувенир = подарок НА ПАМЯТЬ"},
{q:"Найди пример тавтологии",options:["случился случай","солнечный день","высокая гора","добрый человек"],answer:"случился случай",hint:"повтор однокоренных слов"}],
fillblank:[{text:"Лишнее слово в сочетании «главная суть» — ___.",answer:"главная",hint:"суть уже означает главное"},
{text:"Лишнее слово в сочетании «свободная вакансия» — ___.",answer:"свободная",hint:"вакансия = свободное место"}]},

{id:18,category:"gram",task:"№7",title:"Числительные: склонение и употребление",
explanation:"В составных количественных числительных при склонении изменяется каждое слово (с пятьюстами восемьюдесятью тремя рублями). Собирательные числительные (двое, трое, четверо…) не сочетаются с существительными женского рода, но сочетаются с названиями детёнышей, личными местоимениями и словами, имеющими только форму множественного числа (двое суток). Со словами «год» и «раз» при датах склоняется только последнее слово составного порядкового числительного.",
examples:["с пятьюстами рублями (не «пятистами»)","двое саней, трое суток","пятеро студентов, но не «пятеро студенток»","к две тысячи восьмому году"],
mcq:[{q:"Выберите верный вариант",options:["с пятистами рублями","с пятьюстами рублями","с пятьсот рублями","с пятьюсот рублями"],answer:"с пятьюстами рублями"},
{q:"Где ошибка в употреблении числительного?",options:["двое саней","трое студентов","пятеро студенток","четверо друзей"],answer:"пятеро студенток",hint:"собирательные числительные не сочетаются с сущ. женского рода"}],
fillblank:[{text:"Он приехал в город к две тысячи восьм___ году.",answer:"ом",hint:"склоняется только последнее слово составного порядкового числительного"},
{text:"В поле стояло пят___ саней.",answer:"еро",hint:"собирательное числительное с существительным, имеющим только мн.ч."}]},

{id:19,category:"gram",task:"№7",title:"Существительные: род и родительный падеж множественного числа",
explanation:"Некоторые несклоняемые существительные имеют неожиданный род: мужской — пони, кофе, шимпанзе, торнадо; средний — шоссе, какао, портмоне, авокадо; женский — авеню, салями, кольраби. В родительном падеже множественного числа много «ловушек»: одни слова имеют нулевое окончание (яблок, чулок, сапог, партизан, туфель), другие — окончание -ов (носков, помидоров, апельсинов, гектаров).",
examples:["чёрный кофе (м.р.)","вкусное какао (ср.р.)","пара носков, но пара чулок","много помидоров, но много яблок","нет туфель, нет сапог"],
mcq:[{q:"Какое существительное среднего рода?",options:["кофе","пони","какао","шимпанзе"],answer:"какао"},
{q:"Где верная форма родительного падежа мн.ч.?",options:["много помидор","пара носок","нет сапогов","нет чулок"],answer:"нет чулок"}],
fillblank:[{text:"На складе не хватало ___ (сапог, мн.ч. род.п.).",answer:"сапог",hint:"сапог — нулевое окончание"},
{text:"В корзине было много спелых ___ (апельсин, мн.ч. род.п.).",answer:"апельсинов",hint:"апельсинов — окончание -ов"}]},

{id:20,category:"gram",task:"№7",title:"Глаголы, причастия, деепричастия: трудные формы",
explanation:"Некоторые глаголы теряют суффикс -ну- в прошедшем времени (он озяб, а не «озябнул»; иссяк, а не «иссякнул»). Формы повелительного наклонения часто образуются не так, как ожидается: ляг/лягте (не «ляжь»), поезжай (не «ехай»/«едь»). Причастия и деепричастия имеют строгие формы: приведший, изобретший, заперев (не «запёрши»).",
examples:["он озяб (не «озябнул»)","ляг! лягте! (не «ляжь»)","поезжай, поезжайте (не «ехай», «едь»)","приведший, изобретший, приобретший","заперев дверь"],
mcq:[{q:"Какая форма верна?",options:["ляжь","ляг","ляжте","ляжьте"],answer:"ляг"},
{q:"Какая форма верна?",options:["едь быстрее","ехай быстрее","поезжай быстрее","поедь быстрее"],answer:"поезжай быстрее"}],
fillblank:[{text:"Он совсем ___ (озябнуть, кратко, прош.вр.) на морозе.",answer:"озяб",hint:"без суффикса -ну-"},
{text:"___ (ехать, повелит. накл.) осторожно по гололёду!",answer:"поезжай",hint:"верная форма повелительного наклонения"}]},

{id:21,category:"gram",task:"№8",title:"Грамматические ошибки: виды и примеры",
explanation:"Задание 8 требует установить соответствие между видом грамматической ошибки и предложением, в котором она допущена. Основные виды: 1) нарушение связи между подлежащим и сказуемым, 2) ошибка в построении предложения с причастным оборотом, 3) ошибка в построении предложения с деепричастным оборотом, 4) нарушение в построении предложения с однородными членами, 5) ошибка в построении сложного предложения, 6) неправильное построение предложения с косвенной речью, 7) ошибка в употреблении имени числительного, 8) нарушение видо-временной соотнесённости глагольных форм, 9) нарушение норм управления.",
examples:["Те из учеников, кто выполнили домашнее задание, справятся с тестом. (подлежащее — сказуемое)","Используя средства выразительности, текст кажется трудным. (деепричастный оборот)","Согласно приказа, все должны присутствовать. (управление)"],
mcq:[],fillblank:[],
matchPairs:[
  {left:"Нарушение связи между подлежащим и сказуемым",right:"Те из учеников, кто выполнили домашнее задание, справятся с тестом."},
  {left:"Ошибка в построении предложения с причастным оборотом",right:"Ветви обрубили, расположенные слишком низко."},
  {left:"Ошибка в построении предложения с деепричастным оборотом",right:"Используя средства выразительности, текст кажется трудным для восприятия."},
  {left:"Нарушение в построении предложения с однородными членами",right:"Татьяна любила гадать и старинные предания."},
  {left:"Ошибка в построении сложного предложения",right:"Докладчик заострил внимание на вопросе, что нередко поднимается на собраниях."},
  {left:"Неправильное построение предложения с косвенной речью",right:"Пушкин писал, что «берегите наш язык»."},
  {left:"Ошибка в употреблении имени числительного",right:"По дороге шли пятеро монашек."},
  {left:"Нарушение видо-временной соотнесённости глагольных форм",right:"Оазис то показывался, то исчез вдали."},
  {left:"Нарушение норм управления",right:"Согласно приказа, все сотрудники должны присутствовать."}
]}
];
